INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06580', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在社會科學研究中，將經驗世界中某一組類似事物、現象或事件的共同屬性加以萃取出來的活動，稱之 為：', '["資料轉化", "測量", "分析", "抽象化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06581', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '鍾教授為了解社會工作系畢業生的生涯流向，她從2012年社會工作系畢業的學生中，以分層隨機抽樣的方式 抽出180人為樣本，並每2年對樣本進行一次持續性的追蹤調查，預計進行到2024年，樣本流失不予 遞補。以時間架構而言，鍾教授的研究是屬於：', '["趨勢研究（trend study）", "同組研究（panel study）", "世代研究（cohort study）", "橫斷性研究（cross-sectional research）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06582', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於量化研究與質化研究對於「事實」（reality）的理解，下列敍述何者錯誤？', '["質化研究透過所蒐集到的資料來探求變項與變項間的關係，以產生數量化的「事實」", "量化研究認為「事實」是存在於外在客觀的環境中，需透過適當的方法來獲得", "質化研究認為「事實」是由人與非人因素間的動態交互過程所構築起來", "量化研究視世界是一個有秩序、有法則的「事實」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06583', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何者不是解釋主義取向（interpretivism）的質化研究所根基的哲學觀點或理論？', '["現象學", "符號互動論", "邏輯實證論", "詮釋學"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06584', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於文獻探討的敘述，下列何者錯誤？', '["文獻探討可以幫助研究者了解自己研究的重要性，並與先前的研究接軌", "在文獻探討中，要能呈現出自己的意見及想法，避免文獻的堆砌", "藉由文獻探討的過程，研究者可以更清楚要提問什麼樣的研究問題", "為避免研究過程受到理論的過度影響，所以到最後再做文獻探討即可"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06585', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於社會工作研究倫理情境的敘述，下列何者正確？①若在研究過程中參與者表達出想退出研究的意願，', '["為了更突顯質性研究所重視的脈絡關係，應在研究報告中詳述受訪者的個人 背景資料，以保障研究的嚴謹性", "進行質性研究深度訪談時，需徵得受訪者自願參與的同意，同時也 應在訪談前告知研究過程中研究者與受訪者的權利、義務", "為了顧及受訪者的人權及隱私，做質性研 究深度訪談時，不應該直接接觸案主，而是訪談主責社會工作者就好  ⑤為了避免不必要的糾紛，應給 受訪者適當的福利補償", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06586', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '小英社會工作者想了解縣內國中生對十二年國教的看法。她決定採用系統隨機抽樣法（systematic random sampling）來進行抽樣，於是向教育行政單位索取全縣國中教職員生的名冊。假設該縣共有教師1,000人、 職員1,000人、國三學生5,000人、國二學生4,000人、國一學生3,000人，小英想從中抽出1,000人為樣 本。請問小英的抽樣級距（sampling interval）應該是多少？', '["15", "14", "13", "12"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06587', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關機率抽樣（probability sampling）的敘述，下列何者正確？①量化研究一定要依此原則來進行抽樣', '["依此原則進行抽樣，才能將對樣本測量的結果推論回母群體", "依此原則所形成的樣本，才能由樣本 統計數來推估未知的母數", "依此原則所形成的樣本，其分配的特質一定會與母群體完全符合", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06588', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究生使用隨機抽樣的方法進行一份量化研究，且該研究生的研究具有「95%的信賴水準（confidence level）」。請問下列敘述何者錯誤？', '["這代表該研究生以同樣的方式重複進行100次隨機抽樣，可能會有5次抽樣的結果無法代表母群體", "可能有5%的受訪者沒有正確地回答問卷問題", "這代表該研究生重複進行100次隨機抽樣，可能會有95次的調查結果可以正確地包含母群體的母數", "若該研究生想提高其信賴水準至97%時，大量增加有效樣本數是可行方式 情況：李教授針對已在全臺各縣市家暴中心開案的受暴婦女進行調查研究，她以隨機抽樣的方式獲得120位的 隨機樣本。李教授想了解這些婦女的社會階層、社會支持，以及社會工作者的處遇是否對減緩其憂鬱程度 及增進其睡眠品質有所助益。在李教授所設計的問卷中，社會階層是請受訪者自填受測時的每月收入；社 會支持及社會工作者處遇則是由李教授自行設計六個答項，請受訪者勾選其中最具影響力的一項；焦慮程 度是以「貝氏憂鬱量表」（是由21題，每題4點尺度的Likert量表所構成；計算時將各題的得分加總， 分數越高代表憂鬱程度越高）來測量；睡眠品質是以「匹茲堡睡眠品質量表」（是由7題，每題4點尺度 的Likert量表所構成，分數越高代表睡眠品質越差）來測量。請依此回答下列第11題至第14題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06589', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '請問李教授的研究其分析單位是？', '["在家暴中心進行個案處遇的社會工作者", "受暴婦女的個案紀錄", "全臺各縣市的家暴中心", "已在家暴中心開案的受暴婦女"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
